import { GetConfigRequest, GetConfigResponse } from './blob.js';
export class BlobServiceClientJSON {
    constructor(rpc) {
        this.rpc = rpc;
        this.GetConfig.bind(this);
    }
    GetConfig(request) {
        const data = GetConfigRequest.toJSON(request);
        const promise = this.rpc.request('devvit.plugin.blob.v1alpha.BlobService', 'GetConfig', 'application/json', data);
        return promise.then((data) => GetConfigResponse.fromJSON(data));
    }
}
export class BlobServiceClientProtobuf {
    constructor(rpc) {
        this.rpc = rpc;
        this.GetConfig.bind(this);
    }
    GetConfig(request) {
        const data = GetConfigRequest.encode(request).finish();
        const promise = this.rpc.request('devvit.plugin.blob.v1alpha.BlobService', 'GetConfig', 'application/protobuf', data);
        return promise.then((data) => GetConfigResponse.decode(data));
    }
}
